import React, { useState } from 'react';
import ManageUserAccessModal from './ManageUserAccessModal';
import ManageHierarchiesModal from './ManageHierarchiesModal';
import ManageHierarchiesModal3 from './ManageHierarchiesModal3';
import ManageHierarchiesModal2 from './ManageHierarchiesModal2';
import ManageMeasuresModal from './ManageMeasuresModal';

const imgCheckIcon = "data:image/svg+xml,%3Csvg width='15' height='15' viewBox='0 0 15 15' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M3 7.5l3 3 6-6' stroke='white' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E";

const imgCustomAppsIcon = "data:image/svg+xml,%3Csvg width='12' height='12' viewBox='0 0 12 12' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Crect x='2' y='2' width='3' height='3' fill='%230b5cab'/%3E%3Crect x='7' y='2' width='3' height='3' fill='%230b5cab'/%3E%3Crect x='2' y='7' width='3' height='3' fill='%230b5cab'/%3E%3Crect x='7' y='7' width='3' height='3' fill='%230b5cab'/%3E%3C/svg%3E";

const imgSettingsIcon = "data:image/svg+xml,%3Csvg width='12' height='12' viewBox='0 0 12 12' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Ccircle cx='6' cy='6' r='2' stroke='%230b5cab' stroke-width='1.5'/%3E%3Cpath d='M4.5 2l.5 1 1 .5-1 .5-.5 1-.5-1-1-.5 1-.5.5-1zM7.5 7l.5 1 1 .5-1 .5-.5 1-.5-1-1-.5 1-.5.5-1z' fill='%230b5cab'/%3E%3C/svg%3E";

const imgChevronDown = "data:image/svg+xml,%3Csvg width='12' height='12' viewBox='0 0 12 12' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M3 5l3 3 3-3' stroke='%23181818' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E";
const imgCloseIcon = "data:image/svg+xml,%3Csvg width='24' height='24' viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M18 6L6 18M6 6l12 12' stroke='%23666' stroke-width='2' stroke-linecap='round'/%3E%3C/svg%3E";
const imgOrgCalendarPreview = "data:image/png;base64,";

export default function MainContent({
  planningName = 'Commercial Planning and Forecasting',
  onNavigateToPlanningView,
  onNavigateToHierarchySetup,
  onNavigateToMeasuresPage
}) {
  // State for nested step checkboxes
  const [checkboxStates, setCheckboxStates] = useState({
    'step-dimensions': false,
    'step-assortment': false,
    'step-measures': false,
    'step-measure-calculation': false,
    'step-time': true,
    'step-users': true,
    'hierarchy-within': false,
  });

  // Calculate progress for step 1 (based on automatic step 1)
  const getStep1Progress = () => {
    if (!dataCloudEnabled) return 0;
    const totalSteps = 1;
    const completedCount = completedAutoSteps.length;
    return (completedCount / totalSteps) * 100;
  };

  // State for section expand/collapse
  const [expandedSections, setExpandedSections] = useState({
    'required-steps': true,
    'advanced-functionality': false,
    'section-1': true,
    'section-2': true,
    'section-3': true,
    'section-4': true,
  });

  // State for Data Cloud toggle and automatic steps
  const [dataCloudEnabled, setDataCloudEnabled] = useState(true);
  const [completedAutoSteps, setCompletedAutoSteps] = useState([1]);
  const isDataCloudProcessing = dataCloudEnabled && completedAutoSteps.length < 1;
  const isDataCloudProvisioned = dataCloudEnabled && completedAutoSteps.length === 1;
  const [isAssortmentProcessing, setIsAssortmentProcessing] = useState(false);
  const [isAssortmentSuccessful, setIsAssortmentSuccessful] = useState(false);

  // State for modals
  const [isUserAccessModalOpen, setIsUserAccessModalOpen] = useState(false);
  const [isHierarchiesModalM1Open, setIsHierarchiesModalM1Open] = useState(false);
  const [isHierarchiesModalOpen, setIsHierarchiesModalOpen] = useState(false);
  const [isHierarchiesModal2Open, setIsHierarchiesModal2Open] = useState(false);
  const [isMeasuresModalOpen, setIsMeasuresModalOpen] = useState(false);
  const [isFlowPromptOpen, setIsFlowPromptOpen] = useState(false);
  const [isPlanningHorizonModalOpen, setIsPlanningHorizonModalOpen] = useState(false);
  const [currentFlowId, setCurrentFlowId] = useState(null);
  const [measureDmoInputs, setMeasureDmoInputs] = useState({});
  const totalAvailableMeasures = 13;
  const completedDmoCount = Object.values(measureDmoInputs).filter((value) => `${value || ''}`.trim()).length;
  const missingDmoCount = Math.max(totalAvailableMeasures - completedDmoCount, 0);

  const toggleCheckbox = (id) => {
    setCheckboxStates(prev => ({
      ...prev,
      [id]: !prev[id]
    }));
  };

  const toggleSection = (id) => {
    setExpandedSections(prev => ({
      ...prev,
      [id]: !prev[id]
    }));
  };

  const handleDeployDataKits = (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (isDataCloudProcessing || completedAutoSteps.includes(1)) {
      return;
    }

    setDataCloudEnabled(true);
    setCompletedAutoSteps([]);
    setTimeout(() => setCompletedAutoSteps([1]), 900);
  };

  const handleSaveAssortment = (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (isAssortmentProcessing || isAssortmentSuccessful) {
      return;
    }

    setIsAssortmentProcessing(true);
    setCheckboxStates(prev => ({
      ...prev,
      'step-assortment': false
    }));

    setTimeout(() => {
      setCheckboxStates(prev => ({
        ...prev,
        'step-assortment': true
      }));
      setIsAssortmentProcessing(false);
      setIsAssortmentSuccessful(true);
    }, 900);
  };

  const openUserAccessModal = () => setIsUserAccessModalOpen(true);
  const closeUserAccessModal = () => setIsUserAccessModalOpen(false);

  const openHierarchiesModalM1 = () => setIsHierarchiesModalM1Open(true);
  const closeHierarchiesModalM1 = () => setIsHierarchiesModalM1Open(false);

  const openHierarchiesModal = () => setIsHierarchiesModalOpen(true);
  const closeHierarchiesModal = () => setIsHierarchiesModalOpen(false);

  const openHierarchiesModal2 = () => setIsHierarchiesModal2Open(true);
  const closeHierarchiesModal2 = () => setIsHierarchiesModal2Open(false);

  const openMeasuresModal = () => setIsMeasuresModalOpen(true);
  const closeMeasuresModal = () => setIsMeasuresModalOpen(false);

  const openPlanningHorizonModal = () => setIsPlanningHorizonModalOpen(true);
  const closePlanningHorizonModal = () => setIsPlanningHorizonModalOpen(false);

  const openFlowPrompt = (flowId) => {
    setCurrentFlowId(flowId);
    setIsFlowPromptOpen(true);
  };
  
  const closeFlowPrompt = () => {
    if (currentFlowId) {
      const flowToCheckboxMap = {
        'hierarchy-within': 'step-assortment',
      };
      const targetCheckboxId = flowToCheckboxMap[currentFlowId] || currentFlowId;
      setCheckboxStates(prev => ({
        ...prev,
        [targetCheckboxId]: true
      }));
    }
    setIsFlowPromptOpen(false);
    setCurrentFlowId(null);
  };

  // Progress Ring Component
  const ProgressRing = ({ progress }) => {
    const radius = 9;
    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference - (progress / 100) * circumference;
    
    // If 100% complete, show blue filled circle with white checkmark
    if (progress === 100) {
      return (
        <svg width="24" height="24" viewBox="0 0 24 24" className="progress-ring">
          <circle
            cx="12"
            cy="12"
            r="12"
            fill="#0176d3"
          />
          <image href={imgCheckIcon} x="4.5" y="4.5" width="15" height="15" />
        </svg>
      );
    }
    
    // Otherwise show progress ring
    return (
      <svg width="24" height="24" viewBox="0 0 24 24" className="progress-ring">
        {/* Background circle */}
        <circle
          cx="12"
          cy="12"
          r={radius}
          fill="none"
          stroke="#e0e0e0"
          strokeWidth="2"
        />
        {/* Progress circle */}
        <circle
          cx="12"
          cy="12"
          r={radius}
          fill="none"
          stroke="#0176d3"
          strokeWidth="2"
          strokeDasharray={circumference}
          strokeDashoffset={strokeDashoffset}
          strokeLinecap="round"
          transform="rotate(-90 12 12)"
          style={{ transition: 'stroke-dashoffset 0.3s ease' }}
        />
      </svg>
    );
  };

  return (
    <div className="main-content-area">
      {/* Turn On Card */}
      <div className="turn-on-card">
        <div className="turn-on-content">
          <div className="turn-on-text">
            <h2 className="turn-on-title">Turn On {planningName}</h2>
            <div className="turn-on-links">
              <a href="#" className="setup-link">
                <img src={imgSettingsIcon} alt="" />
                <span>Setup Help</span>
              </a>
            </div>
          </div>
          <div className="turn-on-status" role="status" aria-label="Turned On">
            <div className="turn-on-status-icon">
              <img src={imgCheckIcon} alt="" />
            </div>
          </div>
        </div>
      </div>

      {/* Setup Section */}
      <div className="setup-section">
        <div className="setup-section-header" onClick={() => toggleSection('required-steps')} style={{ cursor: 'pointer' }}>
          <img 
            src={imgChevronDown} 
            alt="" 
            className={`chevron-icon ${expandedSections['required-steps'] ? 'expanded' : 'collapsed'}`}
          />
          <div className="setup-section-content">
            <div className="setup-section-title-area">
              <h3 className="setup-section-title">Complete Required Steps</h3>
            </div>
            <p className="setup-section-description">
              Complete the basics, Invoke the pre-built DPEs via salesforce flows and review the out of the box settings
            </p>
          </div>
        </div>

        {/* Steps List */}
        {expandedSections['required-steps'] && (
        <div className="setup-steps">
          {/* Step 1: Enable Data Cloud */}
          <div className="setup-step">
            <div className="step-indicator">
              <div className="step-icon-progress">
                <ProgressRing progress={getStep1Progress()} />
              </div>
            </div>
            <div className="step-content">
              <div className="step-header-row">
                <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px', flex: 1, cursor: 'pointer' }} onClick={() => toggleSection('section-1')}>
                  <img 
                    src={imgChevronDown} 
                    alt="" 
                    className={`step-chevron ${expandedSections['section-1'] ? 'expanded' : 'collapsed'}`}
                  />
                  <div className="step-header-text">
                    <h4 className="step-title">1. Enable Data Cloud</h4>
                    <p className="step-description">
                      Enable Data cloud to ingest, harmonize and unify data across different places
                    </p>
                  </div>
                </div>
                <button
                  className="step-button step-action-link"
                  onClick={handleDeployDataKits}
                >
                  {isDataCloudProcessing ? 'Deploying Data Kits...' : 'Deploy Data Kits'}
                </button>
              </div>
              {expandedSections['section-1'] && (
                <>
                  <a href="#" className="step-link">Learn More in Help</a>

                  {/* Sub-steps */}
                  <div className="sub-step">
                    <div className="sub-step-indicator">
                      <div
                        className={`sub-step-icon ${
                          isDataCloudProcessing
                            ? 'sub-step-icon-processing'
                            : completedAutoSteps.includes(1)
                              ? 'sub-step-icon-blue-completed'
                              : 'sub-step-icon-empty'
                        }`}
                      >
                        {completedAutoSteps.includes(1) && <img src={imgCheckIcon} alt="Completed" />}
                      </div>
                    </div>
                    <div className="sub-step-content">
                      <div className="sub-step-title-row">
                        <h5 className="sub-step-title">Automatic Step 1: Enable Data Kits to create DMOs for the solution</h5>
                        <button className="step-button step-action-link">Review</button>
                      </div>
                    </div>
                  </div>

                  {isDataCloudProcessing && (
                    <p className="step-progress-text data-cloud-progress-text data-cloud-progress-text-processing">Creating Data Kits and required DMOs...</p>
                  )}
                  {isDataCloudProvisioned && (
                    <p className="step-progress-text data-cloud-progress-text data-cloud-progress-text-complete">Data Kits created required DMOs in the system.</p>
                  )}
                </>
              )}
            </div>
          </div>

          {/* Step 1: Review Dimensions & Hierarchies */}
          <div className="setup-step">
            <div className="step-indicator">
              <div 
                className={`step-top-checkbox ${checkboxStates['step-dimensions'] ? 'checked' : ''}`}
                onClick={() => toggleCheckbox('step-dimensions')}
              >
                {checkboxStates['step-dimensions'] && <img src={imgCheckIcon} alt="Checked" />}
              </div>
            </div>
            <div className="step-content">
              <div className="step-header-row" onClick={() => toggleSection('section-2')}>
                <div className="step-header-icon-spacer" />
                <div className="step-header-text">
                  <h4 className="step-title">2. Review Dimensions &amp; Hierarchies</h4>
                  <p className="step-description">Review and make any changes if required to out of the box settings</p>
                </div>
              </div>
              {expandedSections['section-2'] && (
                <>
                  <div className="nested-step">
                    <div className="nested-step-indicator">
                      <div className={`nested-step-checkbox ${checkboxStates['step-dimensions'] ? 'checked' : ''}`} onClick={() => toggleCheckbox('step-dimensions')}>
                        {checkboxStates['step-dimensions'] && <img src={imgCheckIcon} alt="Checked" />}
                      </div>
                    </div>
                    <div className="nested-step-content">
                      <div className="nested-step-main">
                        <div className="nested-step-text">
                          <h6 className="nested-step-title">1.1 Setup the Dimensions and Annotate Hierarchy levels</h6>
                          <p className="nested-step-status">2 Dimensions and 2 hierarchies available</p>
                        </div>
                        <div className="nested-step-buttons">
                          <button className="step-button step-action-link" onClick={openHierarchiesModal2}>Manage Hierarchies</button>
                        </div>
                      </div>
                    </div>
                  </div>
                </>
              )}
            </div>
          </div>

          {/* Step 3: Setup the Measures */}
          <div className="setup-step">
            <div className="step-indicator">
              <div 
                className={`step-top-checkbox ${checkboxStates['step-measures'] ? 'checked' : ''}`}
                onClick={() => toggleCheckbox('step-measures')}
              >
                {checkboxStates['step-measures'] && <img src={imgCheckIcon} alt="Checked" />}
              </div>
            </div>
            <div className="step-content">
              <div className="step-header-row" onClick={() => toggleSection('section-3')}>
                <div className="step-header-icon-spacer" />
                <div className="step-header-text">
                  <h4 className="step-title">3. Setup the Measures</h4>
                  <p className="step-description">View existing or create new measures</p>
                </div>
              </div>
              {expandedSections['section-3'] && (
                <>
                  <div className="nested-step">
                    <div className="nested-step-indicator">
                      <div className={`nested-step-checkbox ${checkboxStates['step-measures'] ? 'checked' : ''}`} onClick={() => toggleCheckbox('step-measures')}>
                        {checkboxStates['step-measures'] && <img src={imgCheckIcon} alt="Checked" />}
                      </div>
                    </div>
                    <div className="nested-step-content">
                      <div className="nested-step-main">
                        <div className="nested-step-text">
                          <h6 className="nested-step-title">3.1 Review measures</h6>
                          <p className="nested-step-status">{missingDmoCount} measures missing DMOs • {completedDmoCount} completed</p>
                        </div>
                        <button className="step-button step-action-link" onClick={openMeasuresModal}>Add Source DMOs</button>
                      </div>
                    </div>
                  </div>

                </>
              )}
            </div>
          </div>

          {/* Step 4: Configure Time Granularity */}
          <div className="setup-step">
            <div className="step-indicator">
              <div 
                className={`step-top-checkbox ${checkboxStates['step-time'] ? 'checked' : ''}`}
                onClick={() => toggleCheckbox('step-time')}
              >
                {checkboxStates['step-time'] && <img src={imgCheckIcon} alt="Checked" />}
              </div>
            </div>
            <div className="step-content">
              <div className="step-header-row">
                <div className="step-header-icon-spacer" />
                <div className="step-header-text">
                  <h4 className="step-title">4. Configure Time Granularity</h4>
                  <p className="step-description">Provide time granularity your product will support</p>
                </div>
              </div>
              <div className="nested-step">
                <div className="nested-step-indicator">
                  <div className="nested-step-checkbox checked">
                    <img src={imgCheckIcon} alt="Checked" />
                  </div>
                </div>
                <div className="nested-step-content">
                  <div className="nested-step-main">
                    <div className="nested-step-text">
                      <h6 className="nested-step-title">4.1 Configure Org Calendar</h6>
                      <p className="nested-step-status">Fiscal Calendar selected by default</p>
                    </div>
                    <button className="step-button step-action-link" onClick={openPlanningHorizonModal}>Go to Org Calendar</button>
                  </div>
                </div>
              </div>
              <div className="nested-step">
                <div className="nested-step-indicator">
                  <div className={`nested-step-checkbox ${checkboxStates['step-time'] ? 'checked' : ''}`} onClick={() => toggleCheckbox('step-time')}>
                    {checkboxStates['step-time'] && <img src={imgCheckIcon} alt="Checked" />}
                  </div>
                </div>
                <div className="nested-step-content">
                  <div className="nested-step-main">
                    <div className="nested-step-text">
                      <h6 className="nested-step-title">4.2 Setup time granularity</h6>
                      <p className="nested-step-status">Provide time granularity your product will support</p>
                    </div>
                    <button className="step-button step-action-link" onClick={openPlanningHorizonModal}>Manage</button>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Step 2: Setup User & User Roles */}
          <div className="setup-step">
            <div className="step-indicator">
              <div 
                className={`step-top-checkbox ${checkboxStates['step-users'] ? 'checked' : ''}`}
                onClick={() => toggleCheckbox('step-users')}
              >
                {checkboxStates['step-users'] && <img src={imgCheckIcon} alt="Checked" />}
              </div>
            </div>
            <div className="step-content">
              <div className="step-header-row">
                <div className="step-header-icon-spacer" />
                <div className="step-header-text">
                  <h4 className="step-title">5. Setup User &amp; User Roles</h4>
                  <p className="step-description">Review and make any changes if required to out of the box settings</p>
                </div>
              </div>
              <div className="nested-step">
                <div className="nested-step-indicator">
                  <div className="nested-step-checkbox checked">
                    <img src={imgCheckIcon} alt="Checked" />
                  </div>
                </div>
                <div className="nested-step-content">
                  <div className="nested-step-main">
                    <div className="nested-step-text">
                      <h6 className="nested-step-title">Setup User Roles</h6>
                      <p className="nested-step-status">10 of 100 assigned</p>
                    </div>
                    <button className="step-button step-action-link" onClick={openUserAccessModal}>Manage</button>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Step 6: Setup Plan Configurations */}
          <div className="setup-step">
            <div className="step-indicator">
              <div className="step-top-checkbox" />
            </div>
            <div className="step-content">
              <div className="step-header-row">
                <div className="step-header-icon-spacer" />
                <div className="step-header-text">
                  <h4 className="step-title">6. Setup Plan Configurations</h4>
                  <p className="step-description">Review or make any minor changes to reuse out of the box plan configuration</p>
                </div>
                <button className="step-button step-action-link" onClick={onNavigateToPlanningView}>Go To Setup</button>
              </div>
            </div>
          </div>
        </div>
        )}
      </div>

      {/* Unlock Advanced Functionality Section */}
      <div className="setup-section">
        <div className="setup-section-header" onClick={() => toggleSection('advanced-functionality')} style={{ cursor: 'pointer' }}>
          <img 
            src={imgChevronDown} 
            alt="" 
            className={`chevron-icon ${expandedSections['advanced-functionality'] ? 'expanded' : 'collapsed'}`}
          />
          <div className="setup-section-content">
            <div className="setup-section-title-area">
              <h3 className="setup-section-title">Unlock advanced Functionality</h3>
            </div>
            <p className="setup-section-description">
              Configure advanced features to enhance your planning and forecasting capabilities
            </p>
          </div>
        </div>

        {/* Steps List for Advanced Functionality */}
        {expandedSections['advanced-functionality'] && (
        <div className="setup-steps">
          {/* Placeholder for advanced functionality steps */}
          <div className="setup-step">
            <div className="step-indicator">
              <div className="step-icon step-icon-empty" />
            </div>
            <div className="step-content">
              <h4 className="step-title">Advanced features coming soon...</h4>
              <p className="step-description">
                Additional configuration options will be available here
              </p>
            </div>
          </div>
        </div>
        )}
      </div>

      {/* Modals */}
      <ManageUserAccessModal isOpen={isUserAccessModalOpen} onClose={closeUserAccessModal} />
      <ManageHierarchiesModal isOpen={isHierarchiesModalM1Open} onClose={closeHierarchiesModalM1} />
      <ManageHierarchiesModal3 isOpen={isHierarchiesModalOpen} onClose={closeHierarchiesModal} />
      <ManageHierarchiesModal2
        isOpen={isHierarchiesModal2Open}
        onClose={closeHierarchiesModal2}
        onGoToHierarchySetup={onNavigateToHierarchySetup}
      />
      <ManageMeasuresModal
        isOpen={isMeasuresModalOpen}
        onClose={closeMeasuresModal}
        onGoToSetupDetails={onNavigateToMeasuresPage}
        sourceDmoInputs={measureDmoInputs}
        onSourceDmoInputsChange={setMeasureDmoInputs}
      />

      {/* Flow Prompt Modal */}
      {isFlowPromptOpen && (
        <div className="modal-overlay" onClick={closeFlowPrompt}>
          <div className="flow-prompt-modal" onClick={(e) => e.stopPropagation()}>
            <div className="flow-prompt-content">
              {currentFlowId === 'hierarchy-within' ? (
                <div className="flow-prompt-item">
                  <div className="flow-prompt-checkmark">
                    <img src={imgCheckIcon} alt="Success" />
                  </div>
                  <p className="flow-prompt-text">Assortment run complete</p>
                </div>
              ) : (
                <>
                  <div className="flow-prompt-item">
                    <div className="flow-prompt-checkmark">
                      <img src={imgCheckIcon} alt="Success" />
                    </div>
                    <p className="flow-prompt-text">Presence of Flow definition is validated</p>
                  </div>
                  <div className="flow-prompt-item">
                    <div className="flow-prompt-checkmark">
                      <img src={imgCheckIcon} alt="Success" />
                    </div>
                    <p className="flow-prompt-text">DPE has been run successfully</p>
                  </div>
                </>
              )}
            </div>
            <button className="flow-prompt-button" onClick={closeFlowPrompt}>OK</button>
          </div>
        </div>
      )}

      {isPlanningHorizonModalOpen && (
        <div className="modal-overlay" onClick={closePlanningHorizonModal}>
          <div className="modal-container modal-container-compact" onClick={(e) => e.stopPropagation()} style={{ width: '1040px', maxWidth: '95vw' }}>
            <div className="modal-header">
              <div className="modal-header-content">
                <h2 className="modal-title">Org Calendar</h2>
              </div>
              <button className="modal-close-button" onClick={closePlanningHorizonModal}>
                <img src={imgCloseIcon} alt="Close" />
              </button>
            </div>
            <div className="modal-body">
              <div className="modal-content" style={{ padding: 0 }}>
                <img
                  src={imgOrgCalendarPreview}
                  alt="Org Calendar preview"
                  style={{ width: '100%', height: 'auto', display: 'block', borderRadius: '4px' }}
                />
              </div>
            </div>
            <div className="modal-footer-buttons" style={{ padding: '0 24px 24px 24px', marginTop: 0, justifyContent: 'flex-end' }}>
              <button className="modal-save-button" onClick={closePlanningHorizonModal}>Done</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
